"use client"

import { type ComponentPropsWithoutRef, useRef } from "react"
import gsap from "gsap"
import { useGSAP } from "@gsap/react"

import { cn } from "@/lib/utils"
import { usePrefersReducedMotion } from "@/hooks/use-prefers-reduced-motion"

type GlassFolderProps = ComponentPropsWithoutRef<"figure"> & {
  label?: string
  folderLabel?: string
  ctaLabel?: string
  noteLabel?: string
  items?: GlassFolderItem[]
}

export type GlassFolderItem = {
  title: string
  description?: string
  href?: string
  badge?: string
  actionLabel?: string
}

const paperLines = [
  ["w-[78%]", "w-[62%]"],
  ["w-[66%]", "w-[80%]"],
  ["w-[58%]", "w-[74%]"],
]

const defaultItems: GlassFolderItem[] = [
  {
    title: "Brief",
    description: "Goals, owner, kickoff links.",
    href: "#",
    badge: "Info",
    actionLabel: "Open",
  },
  {
    title: "Assets",
    description: "Screens, specs, tokens.",
    href: "#",
    badge: "Kit",
    actionLabel: "Open",
  },
  {
    title: "Roadmap",
    description: "Milestones and notes.",
    href: "#",
    badge: "Plan",
    actionLabel: "Open",
  },
]

const paperPlacements = [
  "left-[30%]",
  "left-1/2 z-10",
  "left-[70%]",
]

export function GlassFolder({
  label = "Frosted folder with layered documents",
  folderLabel = "Workspace",
  ctaLabel = "Open",
  noteLabel = "Note",
  items = defaultItems,
  className,
  onPointerEnter,
  onPointerLeave,
  ...props
}: GlassFolderProps) {
  const rootRef = useRef<HTMLElement>(null)
  const folderBackRef = useRef<HTMLDivElement>(null)
  const folderFrontRef = useRef<HTMLDivElement>(null)
  const glowRef = useRef<HTMLDivElement>(null)
  const reducedMotion = usePrefersReducedMotion()
  const folderItems = items.length > 0 ? items : defaultItems

  useGSAP(
    () => {
      if (!rootRef.current) {
        return
      }

      const papers = gsap.utils.toArray<HTMLElement>("[data-folder-paper]")
      const lines = gsap.utils.toArray<HTMLElement>("[data-folder-line]")

      gsap.set(rootRef.current, {
        clearProps: "transform",
        opacity: 1,
      })

      gsap.set(papers, {
        transformOrigin: "50% 100%",
        x: 0,
        y: 0,
        opacity: 1,
        rotate: (index) => [-6, 0, 6][index] ?? 0,
      })

      gsap.set(lines, {
        scaleX: 1,
        opacity: 1,
      })

      gsap.set([folderFrontRef.current, folderBackRef.current, glowRef.current], {
        clearProps: "transform",
      })
    },
    { dependencies: [reducedMotion], scope: rootRef }
  )

  return (
    <figure
      ref={rootRef}
      aria-label={label}
      className={cn(
        "group/folder relative isolate mx-auto aspect-[1.18] w-[min(27rem,calc(100vw-3rem))] cursor-default select-none [perspective:900px]",
        className
      )}
      onPointerEnter={(event) => {
        onPointerEnter?.(event)

        if (reducedMotion || !rootRef.current) {
          return
        }

        const papers = gsap.utils.toArray<HTMLElement>(
          rootRef.current.querySelectorAll("[data-folder-paper]")
        )
        const animatedTargets = [
          rootRef.current,
          folderFrontRef.current,
          folderBackRef.current,
          glowRef.current,
          ...papers,
        ].filter(Boolean)

        gsap.killTweensOf(animatedTargets)

        const fanOffset = rootRef.current.getBoundingClientRect().width * 0.13

        gsap.to(papers, {
          y: (index) => [-54, -70, -54][index] ?? -54,
          x: (index) => [-fanOffset, 0, fanOffset][index] ?? 0,
          rotate: (index) => [-9, 0, 9][index] ?? 0,
          duration: 0.58,
          ease: "elastic.out(1, 0.62)",
          stagger: 0.035,
        })

        gsap.to(folderFrontRef.current, {
          y: 18,
          scaleY: 0.92,
          duration: 0.42,
          ease: "power3.out",
        })

        gsap.to(folderBackRef.current, {
          y: -8,
          duration: 0.42,
          ease: "power3.out",
        })

        gsap.to(glowRef.current, {
          opacity: 0.95,
          scale: 1.18,
          duration: 0.42,
          ease: "power3.out",
        })
      }}
      onPointerLeave={(event) => {
        onPointerLeave?.(event)

        if (reducedMotion || !rootRef.current) {
          return
        }

        const papers = gsap.utils.toArray<HTMLElement>(
          rootRef.current.querySelectorAll("[data-folder-paper]")
        )
        const animatedTargets = [
          rootRef.current,
          folderFrontRef.current,
          folderBackRef.current,
          glowRef.current,
          ...papers,
        ].filter(Boolean)

        gsap.killTweensOf(animatedTargets)

        gsap.set(rootRef.current, {
          clearProps: "transform",
        })

        gsap.to(papers, {
          x: 0,
          y: 0,
          rotate: (index) => [-6, 0, 6][index] ?? 0,
          duration: 0.58,
          ease: "elastic.out(1, 0.58)",
          stagger: 0.04,
        })

        gsap.to([folderFrontRef.current, folderBackRef.current], {
          y: 0,
          scaleY: 1,
          duration: 0.55,
          ease: "power3.out",
        })

        gsap.to(glowRef.current, {
          opacity: 1,
          scale: 1,
          duration: 0.45,
          ease: "power3.out",
        })
      }}
      {...props}
    >
      <div
        ref={glowRef}
        aria-hidden="true"
        className="absolute inset-x-[11%] bottom-[1%] -z-20 h-[18%] rounded-full bg-[#51afe3]/28 blur-2xl"
      />
      <div
        aria-hidden="true"
        className="absolute inset-[10%] -z-10 rounded-[2rem] bg-[#8fd5ff]/16 blur-3xl"
      />

      <div className="absolute inset-x-[9%] bottom-[13%] h-[65%] [transform-style:preserve-3d]">
        <div
          ref={folderBackRef}
          className="absolute inset-x-[5%] bottom-[17%] h-[74%] rounded-[1.35rem] border border-white/30 bg-[linear-gradient(180deg,rgba(130,209,249,0.92),rgba(68,169,224,0.86))] shadow-[inset_0_1px_8px_rgba(255,255,255,0.42),0_28px_60px_rgba(37,126,184,0.26)]"
        />
        <div className="absolute left-[5%] top-[6%] h-[22%] w-[44%] rounded-t-[1.35rem] bg-[linear-gradient(180deg,rgba(135,214,251,0.94),rgba(85,183,232,0.88))]" />

        {paperLines.map((lines, paperIndex) => {
          const item = folderItems[paperIndex % folderItems.length] ?? defaultItems[paperIndex]
          const actionLabel = item.actionLabel ?? (item.href ? ctaLabel : noteLabel)
          const content = (
            <>
              <div className="flex min-w-0 items-center justify-between gap-1.5">
                <span className="min-w-0 truncate rounded-full bg-[#e5f6ff] px-1.5 py-0.5 text-[0.48rem] font-bold uppercase tracking-wide text-[#2d86b7]">
                  {item.badge ?? `Item ${paperIndex + 1}`}
                </span>
                <span className="max-w-[3.4rem] shrink-0 truncate rounded-full bg-[#61b9e9]/16 px-1.5 py-0.5 text-[0.5rem] font-bold text-[#227aaa]">
                  {actionLabel}
                </span>
              </div>
              <div className="mt-3 min-w-0 text-left">
                <p className="truncate text-[0.72rem] font-bold leading-tight text-[#164f74]">
                  {item.title}
                </p>
                <p className="mt-1 overflow-hidden text-[0.54rem] font-semibold leading-snug text-[#4f91b5] [display:-webkit-box] [-webkit-box-orient:vertical] [-webkit-line-clamp:2]">
                  {item.description ?? "Add a link, note, or resource."}
                </p>
              </div>
              <div className="mt-auto space-y-1.5 pt-2">
                {lines.slice(0, 2).map((width, lineIndex) => (
                  <div key={lineIndex} className="grid grid-cols-[1fr_0.55fr] gap-2">
                    <span
                      data-folder-line
                      className={cn(
                        "h-1 max-w-full origin-left rounded-full bg-[#8ed2f3]/70",
                        width
                      )}
                    />
                    <span
                      data-folder-line
                      className="h-1 origin-left rounded-full bg-[#8ed2f3]/45"
                    />
                  </div>
                ))}
              </div>
            </>
          )
          const paperClassName = cn(
            "absolute bottom-[30%] flex h-[57%] w-[34%] -translate-x-1/2 flex-col overflow-hidden rounded-[1rem] border border-[#d9f3ff] bg-[#f8fcfe] p-2.5 text-left no-underline shadow-[0_14px_30px_rgba(30,91,132,0.13)] outline-none transition-[border-color,box-shadow] hover:border-[#b7e8ff] hover:shadow-[0_18px_34px_rgba(30,91,132,0.22)] focus-visible:border-[#50b7e9] focus-visible:shadow-[0_0_0_3px_rgba(80,183,233,0.24),0_18px_34px_rgba(30,91,132,0.2)]",
            paperPlacements[paperIndex]
          )

          return item.href ? (
            <a
              key={paperIndex}
              data-folder-paper
              href={item.href}
              className={paperClassName}
            >
              {content}
            </a>
          ) : (
            <div
              key={paperIndex}
              data-folder-paper
              className={paperClassName}
            >
              {content}
            </div>
          )
        })}

        <div
          ref={folderFrontRef}
          className="absolute inset-x-0 bottom-0 z-20 h-[55%] overflow-hidden rounded-b-[1.55rem] rounded-t-[1.15rem] border border-white/30 bg-[linear-gradient(180deg,rgba(163,225,255,0.62),rgba(64,170,226,0.78))] shadow-[inset_0_1px_10px_rgba(255,255,255,0.5),inset_0_-24px_42px_rgba(50,146,203,0.16),0_22px_52px_rgba(24,106,164,0.28)] backdrop-blur-md"
        >
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_26%_12%,rgba(255,255,255,0.58),transparent_32%),linear-gradient(110deg,rgba(255,255,255,0.38),transparent_34%,rgba(255,255,255,0.18)_64%,transparent)]" />
          <div className="absolute inset-x-[12%] top-[26%] space-y-3 opacity-45 blur-[1.4px]">
            {Array.from({ length: 6 }).map((_, index) => (
              <div key={index} className="grid grid-cols-[1fr_0.8fr] gap-4">
                <span className="h-2 rounded-full bg-[#2f9ed7]/48" />
                <span className="h-2 rounded-full bg-[#2f9ed7]/36" />
              </div>
            ))}
          </div>
          <div className="absolute bottom-4 left-5 rounded-full border border-white/35 bg-white/28 px-3 py-1 text-[0.68rem] font-bold text-[#176f9e] shadow-[0_8px_22px_rgba(52,143,197,0.16)] backdrop-blur-md">
            {folderLabel}
          </div>
        </div>
      </div>
    </figure>
  )
}

"use client"

import { useSyncExternalStore } from "react"

const reducedMotionQuery = "(prefers-reduced-motion: reduce)"

function subscribe(onStoreChange: () => void) {
  const mediaQuery = window.matchMedia(reducedMotionQuery)

  mediaQuery.addEventListener("change", onStoreChange)

  return () => {
    mediaQuery.removeEventListener("change", onStoreChange)
  }
}

function getSnapshot() {
  return window.matchMedia(reducedMotionQuery).matches
}

function getServerSnapshot() {
  return false
}

export function usePrefersReducedMotion() {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot)
}
